# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

def get_user_permission(user_id, file_id):
    conn = sqlite3.connect('permissions.db')
    cursor = conn.cursor()
    query = "SELECT permission FROM user_file_permissions WHERE user_id=? AND file_id=?"
    cursor.execute(query, (user_id, file_id))
    result = cursor.fetchone()
    conn.close()
    return result[0] if result else 'none'

def read_file(user_id, file_path):
    file_id = hash(file_path)  # Simple hash for demonstration purposes
    permission = get_user_permission(user_id, file_id)
    
    if permission == 'read':
        with open(file_path, 'r') as file:
            return file.read()
    elif permission == 'none':
        raise PermissionError("User does not have read access to this file.")
    else:
        raise Exception("Unknown permission level.")

# Example usage
try:
    content = read_file('user123', '/path/to/document.txt')
    print(content)
except (PermissionError, Exception) as e:
    print(e)